package com.careeros.resume.infrastructure;import com.careeros.resume.domain.*;import org.springframework.data.domain.*;import org.springframework.data.jpa.repository.*;import org.springframework.stereotype.Repository;import java.util.*;
interface SpringDataResumeVersionRepository extends JpaRepository<ResumeVersion,UUID>{@EntityGraph(attributePaths="job")List<ResumeVersion>findByJobIdOrderByCreatedAtDesc(UUID id);@Query("select coalesce(max(r.versionNumber),0)+1 from ResumeVersion r")int nextVersion();@EntityGraph(attributePaths="job")Page<ResumeVersion>findAll(Pageable p);}
@Repository class ResumeVersionRepositoryAdapter implements ResumeVersionRepository{private final SpringDataResumeVersionRepository r;ResumeVersionRepositoryAdapter(SpringDataResumeVersionRepository r){this.r=r;}public ResumeVersion save(ResumeVersion v){return r.save(v);}public Optional<ResumeVersion>findById(UUID id){return r.findById(id);}public Page<ResumeVersion>findAll(Pageable p){return r.findAll(p);}public List<ResumeVersion>findByJobId(UUID id){return r.findByJobIdOrderByCreatedAtDesc(id);}public int nextVersion(){return r.nextVersion();}public void delete(ResumeVersion v){r.delete(v);}}
